mapper.update:
UPDATE sys_article SET quantity = CASE
WHEN id = #{article.id} THEN #{article.quantity}
END WHERE id IN
#{article.id}

mapper.select:
SELECT a.id, a.title, a.summary, a.cover, a.is_stick, a.is_recommend, a.quantity, a.status, a.create_time, c.name AS categoryName, u.nickname, u.avatar FROM sys_article a LEFT JOIN sys_category c ON a.category_id = c.id left join sys_user u on a.user_id = u.id
a.status = #{query.status}
and a.title like concat('%',#{query.title},'%')
and a.category_id = #{query.categoryId}
AND EXISTS ( SELECT 1 FROM sys_article_tag sat WHERE sat.article_id = a.id AND sat.tag_id = #{query.tagId} )
order by a.is_stick desc, a.create_time desc

SELECT a.id, a.title, a.summary, a.cover, a.quantity, a.is_stick, a.status, a.create_time, c.name AS categoryName, COALESCE(sc.comment_num, 0) AS commentNum, COALESCE(sal.like_num, 0) AS likeNum FROM sys_article a LEFT JOIN sys_category c ON a.category_id = c.id LEFT JOIN ( SELECT article_id, COUNT(id) AS comment_num FROM sys_comment GROUP BY article_id ) sc ON sc.article_id = a.id LEFT JOIN ( SELECT article_id, COUNT(id) AS like_num FROM sys_article_like GROUP BY article_id ) sal ON sal.article_id = a.id WHERE a.user_id = #{article.userId}
AND a.status = #{article.status}
AND a.title like concat('%',#{article.title},'%')
order by a.is_stick desc, a.create_time desc
